use argon2::{Argon2, PasswordHash, PasswordHasher, PasswordVerifier, password_hash::SaltString};
use delta_core::models::user::User;
use delta_core::{DeltaError, Result, db};
use sqlx::SqlitePool;

/// Hash a password with argon2.
pub fn hash_password(password: &str) -> Result<String> {
    let salt = SaltString::generate(&mut argon2::password_hash::rand_core::OsRng);
    let argon2 = Argon2::default();
    let hash = argon2
        .hash_password(password.as_bytes(), &salt)
        .map_err(|e| DeltaError::AuthFailed(e.to_string()))?;
    Ok(hash.to_string())
}

/// Verify a password against its hash.
pub fn verify_password(password: &str, hash: &str) -> Result<bool> {
    let parsed = PasswordHash::new(hash).map_err(|e| DeltaError::AuthFailed(e.to_string()))?;
    Ok(Argon2::default()
        .verify_password(password.as_bytes(), &parsed)
        .is_ok())
}

/// Generate a random API token. Returns (raw_token, hash).
pub fn generate_token() -> Result<(String, String)> {
    use base64::Engine;
    let mut bytes = [0u8; 32];
    getrandom::fill(&mut bytes).map_err(|e| DeltaError::Storage(format!("RNG failure: {}", e)))?;
    let raw = format!(
        "delta_{}",
        base64::engine::general_purpose::URL_SAFE_NO_PAD.encode(bytes),
    );
    let hash = blake3::hash(raw.as_bytes()).to_hex().to_string();
    Ok((raw, hash))
}

/// Hash a raw token for lookup.
pub fn hash_token(raw: &str) -> String {
    blake3::hash(raw.as_bytes()).to_hex().to_string()
}

/// Authenticate a user by token. Returns the user if valid.
pub async fn authenticate_token(pool: &SqlitePool, raw_token: &str) -> Result<User> {
    let token_hash = hash_token(raw_token);
    db::user::get_by_token_hash(pool, &token_hash)
        .await?
        .ok_or_else(|| DeltaError::AuthFailed("invalid or expired token".into()))
}

/// Register a new user. Returns the user.
pub async fn register(
    pool: &SqlitePool,
    username: &str,
    email: &str,
    password: &str,
    is_agent: bool,
) -> Result<User> {
    let pw_hash = hash_password(password)?;
    db::user::create(pool, username, email, &pw_hash, is_agent).await
}

/// Compute token expiry timestamp from config.
pub fn compute_expiry(expiry_secs: u64) -> Option<String> {
    if expiry_secs == 0 {
        return None;
    }
    let expires = chrono::Utc::now() + chrono::Duration::seconds(expiry_secs as i64);
    Some(expires.to_rfc3339())
}

/// Login with username/password. Returns (user, raw_token).
pub async fn login(
    pool: &SqlitePool,
    username: &str,
    password: &str,
    token_expiry_secs: u64,
) -> Result<(User, String)> {
    let (user_id, pw_hash) = db::user::get_password_hash(pool, username).await?;

    if !verify_password(password, &pw_hash)? {
        return Err(DeltaError::AuthFailed("invalid credentials".into()));
    }

    let (raw_token, token_hash) = generate_token()?;
    let expires_at = compute_expiry(token_expiry_secs);
    db::user::create_token(
        pool,
        &user_id,
        "login",
        &token_hash,
        "*",
        expires_at.as_deref(),
    )
    .await?;

    let user = db::user::get_by_id(pool, &user_id).await?;
    Ok((user, raw_token))
}

use axum::{
    extract::FromRequestParts,
    http::{StatusCode, request::Parts},
};
use delta_core::models::user::User;

use crate::auth;
use crate::state::AppState;

/// Extractor that authenticates the request via Bearer token.
/// Rejects with 401 if no valid token is provided.
pub struct AuthUser(pub User);

impl FromRequestParts<AppState> for AuthUser {
    type Rejection = (StatusCode, &'static str);

    async fn from_request_parts(
        parts: &mut Parts,
        state: &AppState,
    ) -> std::result::Result<Self, Self::Rejection> {
        let header = parts
            .headers
            .get("authorization")
            .and_then(|v| v.to_str().ok())
            .ok_or((StatusCode::UNAUTHORIZED, "missing authorization header"))?;

        let token = header
            .strip_prefix("Bearer ")
            .ok_or((StatusCode::UNAUTHORIZED, "invalid authorization format"))?;

        let user = auth::authenticate_token(&state.db, token)
            .await
            .map_err(|_| (StatusCode::UNAUTHORIZED, "invalid or expired token"))?;

        Ok(AuthUser(user))
    }
}

/// Optional auth — returns None if no token provided, errors if token is invalid.
pub struct MaybeAuthUser(pub Option<User>);

impl FromRequestParts<AppState> for MaybeAuthUser {
    type Rejection = (StatusCode, &'static str);

    async fn from_request_parts(
        parts: &mut Parts,
        state: &AppState,
    ) -> std::result::Result<Self, Self::Rejection> {
        let header = parts
            .headers
            .get("authorization")
            .and_then(|v| v.to_str().ok());

        match header {
            None => Ok(MaybeAuthUser(None)),
            Some(h) => {
                let token = h
                    .strip_prefix("Bearer ")
                    .ok_or((StatusCode::UNAUTHORIZED, "invalid authorization format"))?;

                let user = auth::authenticate_token(&state.db, token)
                    .await
                    .map_err(|_| (StatusCode::UNAUTHORIZED, "invalid or expired token"))?;

                Ok(MaybeAuthUser(Some(user)))
            }
        }
    }
}

//! Shared helper functions for route handlers.

use axum::http::StatusCode;
use delta_core::db;
use delta_core::models::repo::{Repository, Visibility};
use delta_core::models::user::User;

use crate::state::AppState;

/// Resolve a repository by owner username and repo name.
/// Returns (Repository, owner User).
///
/// **Important**: For endpoints that accept `AuthUser`, pass the user to
/// `resolve_repo_authed` instead, which enforces private repo visibility.
pub async fn resolve_repo(
    state: &AppState,
    owner: &str,
    name: &str,
) -> Result<(Repository, User), (StatusCode, String)> {
    let owner_user = db::user::get_by_username(&state.db, owner)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "user not found".into()))?;
    let owner_id = owner_user.id.to_string();
    let repo = db::repo::get_by_owner_and_name(&state.db, &owner_id, name)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "repository not found".into()))?;

    // Block access to non-public repos when called without a user context.
    // Endpoints with AuthUser should use resolve_repo_authed instead.
    if repo.visibility != Visibility::Public {
        return Err((StatusCode::NOT_FOUND, "repository not found".into()));
    }

    Ok((repo, owner_user))
}

/// Resolve a repository and enforce visibility for the authenticated user.
/// Private repos are only visible to the owner.
pub async fn resolve_repo_authed(
    state: &AppState,
    owner: &str,
    name: &str,
    user: &User,
) -> Result<(Repository, User), (StatusCode, String)> {
    let owner_user = db::user::get_by_username(&state.db, owner)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "user not found".into()))?;
    let owner_id = owner_user.id.to_string();
    let repo = db::repo::get_by_owner_and_name(&state.db, &owner_id, name)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "repository not found".into()))?;

    if repo.visibility != Visibility::Public && user.id != owner_user.id {
        return Err((StatusCode::NOT_FOUND, "repository not found".into()));
    }

    Ok((repo, owner_user))
}

