//! Phase 7/8: Audit log API routes.

use axum::{
    Json, Router,
    extract::{Query, State},
    http::StatusCode,
    routing::get,
};
use delta_core::db;
use serde::Deserialize;

use crate::extractors::AuthUser;
use crate::state::AppState;

pub fn router() -> Router<AppState> {
    Router::new().route("/", get(list_audit_log))
}

#[derive(Deserialize)]
struct AuditQuery {
    user_id: Option<String>,
    resource_type: Option<String>,
    #[serde(default = "default_limit")]
    limit: i64,
    #[serde(default)]
    offset: i64,
}
fn default_limit() -> i64 {
    100
}

async fn list_audit_log(
    State(state): State<AppState>,
    AuthUser(user): AuthUser,
    Query(query): Query<AuditQuery>,
) -> Result<Json<Vec<db::audit::AuditEntry>>, (StatusCode, String)> {
    let own_id = user.id.to_string();

    // Users can only view their own audit logs
    if let Some(ref requested_id) = query.user_id
        && *requested_id != own_id
    {
        return Err((
            StatusCode::FORBIDDEN,
            "cannot view another user's audit log".into(),
        ));
    }

    let limit = query.limit.clamp(1, 500);
    let entries = db::audit::list(
        &state.db,
        Some(&own_id),
        query.resource_type.as_deref(),
        limit,
        query.offset.max(0),
    )
    .await
    .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, e.to_string()))?;
    Ok(Json(entries))
}

use axum::{Json, Router, extract::State, http::StatusCode, routing::post};
use serde::{Deserialize, Serialize};

use crate::auth;
use crate::extractors::AuthUser;
use crate::state::AppState;

pub fn router() -> Router<AppState> {
    Router::new()
        .route("/register", post(register))
        .route("/login", post(login))
        .route("/tokens", post(create_token))
}

#[derive(Deserialize)]
struct RegisterRequest {
    username: String,
    email: String,
    password: String,
    #[serde(default)]
    is_agent: bool,
}

#[derive(Serialize)]
struct AuthResponse {
    user: UserResponse,
    token: String,
}

#[derive(Serialize)]
struct UserResponse {
    id: String,
    username: String,
    email: String,
    is_agent: bool,
}

async fn register(
    State(state): State<AppState>,
    Json(req): Json<RegisterRequest>,
) -> Result<(StatusCode, Json<AuthResponse>), (StatusCode, String)> {
    // Validate username: 1-39 chars, alphanumeric and hyphens, no leading hyphen
    if req.username.is_empty()
        || req.username.len() > 39
        || req.username.starts_with('-')
        || !req
            .username
            .chars()
            .all(|c| c.is_ascii_alphanumeric() || c == '-')
    {
        return Err((
            StatusCode::BAD_REQUEST,
            "username must be 1-39 alphanumeric characters or hyphens, not starting with '-'"
                .into(),
        ));
    }
    if req.password.len() < 8 {
        return Err((
            StatusCode::BAD_REQUEST,
            "password must be at least 8 characters".into(),
        ));
    }
    let user = auth::register(
        &state.db,
        &req.username,
        &req.email,
        &req.password,
        req.is_agent,
    )
    .await
    .map_err(|e| (StatusCode::CONFLICT, e.to_string()))?;

    let (raw_token, token_hash) =
        auth::generate_token().map_err(|e| {
        tracing::error!("internal error: {}", e);
        (StatusCode::INTERNAL_SERVER_ERROR, "internal server error".into())
    })?;
    let expires_at = auth::compute_expiry(state.config.auth.token_expiry_secs);
    delta_core::db::user::create_token(
        &state.db,
        &user.id.to_string(),
        "initial",
        &token_hash,
        "*",
        expires_at.as_deref(),
    )
    .await
    .map_err(|e| {
        tracing::error!("internal error: {}", e);
        (StatusCode::INTERNAL_SERVER_ERROR, "internal server error".into())
    })?;

    Ok((
        StatusCode::CREATED,
        Json(AuthResponse {
            user: UserResponse {
                id: user.id.to_string(),
                username: user.username,
                email: user.email,
                is_agent: user.is_agent,
            },
            token: raw_token,
        }),
    ))
}

#[derive(Deserialize)]
struct LoginRequest {
    username: String,
    password: String,
}

async fn login(
    State(state): State<AppState>,
    Json(req): Json<LoginRequest>,
) -> Result<Json<AuthResponse>, (StatusCode, String)> {
    let (user, token) = auth::login(
        &state.db,
        &req.username,
        &req.password,
        state.config.auth.token_expiry_secs,
    )
    .await
    .map_err(|e| (StatusCode::UNAUTHORIZED, e.to_string()))?;

    Ok(Json(AuthResponse {
        user: UserResponse {
            id: user.id.to_string(),
            username: user.username,
            email: user.email,
            is_agent: user.is_agent,
        },
        token,
    }))
}

#[derive(Deserialize)]
struct CreateTokenRequest {
    name: String,
    #[serde(default = "default_scopes")]
    scopes: String,
}

fn default_scopes() -> String {
    "*".to_string()
}

#[derive(Serialize)]
struct TokenResponse {
    id: String,
    token: String,
}

async fn create_token(
    State(state): State<AppState>,
    AuthUser(user): AuthUser,
    Json(req): Json<CreateTokenRequest>,
) -> Result<(StatusCode, Json<TokenResponse>), (StatusCode, String)> {
    let (raw_token, token_hash) =
        auth::generate_token().map_err(|e| {
        tracing::error!("internal error: {}", e);
        (StatusCode::INTERNAL_SERVER_ERROR, "internal server error".into())
    })?;
    let expires_at = auth::compute_expiry(state.config.auth.token_expiry_secs);
    let id = delta_core::db::user::create_token(
        &state.db,
        &user.id.to_string(),
        &req.name,
        &token_hash,
        &req.scopes,
        expires_at.as_deref(),
    )
    .await
    .map_err(|e| {
        tracing::error!("internal error: {}", e);
        (StatusCode::INTERNAL_SERVER_ERROR, "internal server error".into())
    })?;

    Ok((
        StatusCode::CREATED,
        Json(TokenResponse {
            id,
            token: raw_token,
        }),
    ))
}

use axum::{
    Json, Router,
    extract::{Path, State},
    http::StatusCode,
    routing::get,
};
use serde::{Deserialize, Serialize};

use crate::extractors::AuthUser;
use crate::helpers::resolve_repo_authed;
use crate::state::AppState;

pub fn router() -> Router<AppState> {
    Router::new()
        .route("/{owner}/{name}/branches", get(list_branches))
        .route("/{owner}/{name}/tags", get(list_tags))
        .route(
            "/{owner}/{name}/branch-protections",
            get(list_protections).post(create_protection),
        )
        .route(
            "/{owner}/{name}/branch-protections/{protection_id}",
            axum::routing::delete(delete_protection),
        )
}

async fn list_branches(
    State(state): State<AppState>,
    Path((owner, name)): Path<(String, String)>,
    AuthUser(user): AuthUser,
) -> Result<Json<Vec<delta_vcs::refs::BranchInfo>>, (StatusCode, String)> {
    // Enforce visibility check for private repos
    let _ = resolve_repo_authed(&state, &owner, &name, &user).await?;

    let repo_path = state
        .repo_host
        .repo_path(&owner, &name)
        .map_err(|e| (StatusCode::BAD_REQUEST, e.to_string()))?;
    if !repo_path.exists() {
        return Err((StatusCode::NOT_FOUND, "repository not found".into()));
    }

    let branches = delta_vcs::refs::list_branches(&repo_path)
        .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, e.to_string()))?;

    Ok(Json(branches))
}

async fn list_tags(
    State(state): State<AppState>,
    Path((owner, name)): Path<(String, String)>,
    AuthUser(user): AuthUser,
) -> Result<Json<Vec<delta_vcs::refs::TagInfo>>, (StatusCode, String)> {
    // Enforce visibility check for private repos
    let _ = resolve_repo_authed(&state, &owner, &name, &user).await?;

    let repo_path = state
        .repo_host
        .repo_path(&owner, &name)
        .map_err(|e| (StatusCode::BAD_REQUEST, e.to_string()))?;
    if !repo_path.exists() {
        return Err((StatusCode::NOT_FOUND, "repository not found".into()));
    }

    let tags = delta_vcs::refs::list_tags(&repo_path)
        .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, e.to_string()))?;

    Ok(Json(tags))
}

#[derive(Serialize)]
struct ProtectionResponse {
    id: String,
    pattern: String,
    require_pr: bool,
    required_approvals: u32,
    require_status_checks: bool,
    prevent_force_push: bool,
    prevent_deletion: bool,
}

async fn list_protections(
    State(state): State<AppState>,
    Path((owner, name)): Path<(String, String)>,
    AuthUser(user): AuthUser,
) -> Result<Json<Vec<ProtectionResponse>>, (StatusCode, String)> {
    let owner_user = delta_core::db::user::get_by_username(&state.db, &owner)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "user not found".into()))?;

    if user.id != owner_user.id {
        return Err((StatusCode::FORBIDDEN, "not the repository owner".into()));
    }

    let owner_id = owner_user.id.to_string();
    let repo = delta_core::db::repo::get_by_owner_and_name(&state.db, &owner_id, &name)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "repository not found".into()))?;

    let protections =
        delta_core::db::branch_protection::list_for_repo(&state.db, &repo.id.to_string())
            .await
            .map_err(|e| {
                tracing::error!("failed to list branch protections: {}", e);
                (StatusCode::INTERNAL_SERVER_ERROR, "internal server error".into())
            })?;

    Ok(Json(
        protections
            .into_iter()
            .map(|p| ProtectionResponse {
                id: p.id.to_string(),
                pattern: p.pattern,
                require_pr: p.require_pr,
                required_approvals: p.required_approvals,
                require_status_checks: p.require_status_checks,
                prevent_force_push: p.prevent_force_push,
                prevent_deletion: p.prevent_deletion,
            })
            .collect(),
    ))
}

#[derive(Deserialize)]
struct CreateProtectionRequest {
    pattern: String,
    #[serde(default)]
    require_pr: bool,
    #[serde(default)]
    required_approvals: u32,
    #[serde(default)]
    require_status_checks: bool,
    #[serde(default = "default_true")]
    prevent_force_push: bool,
    #[serde(default = "default_true")]
    prevent_deletion: bool,
}

fn default_true() -> bool {
    true
}

async fn create_protection(
    State(state): State<AppState>,
    Path((owner, name)): Path<(String, String)>,
    AuthUser(user): AuthUser,
    Json(req): Json<CreateProtectionRequest>,
) -> Result<(StatusCode, Json<ProtectionResponse>), (StatusCode, String)> {
    let owner_user = delta_core::db::user::get_by_username(&state.db, &owner)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "user not found".into()))?;

    if user.id != owner_user.id {
        return Err((StatusCode::FORBIDDEN, "not the repository owner".into()));
    }

    let owner_id = owner_user.id.to_string();
    let repo = delta_core::db::repo::get_by_owner_and_name(&state.db, &owner_id, &name)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "repository not found".into()))?;

    let protection = delta_core::db::branch_protection::create(
        &state.db,
        delta_core::db::branch_protection::CreateParams {
            repo_id: &repo.id.to_string(),
            pattern: &req.pattern,
            require_pr: req.require_pr,
            required_approvals: req.required_approvals,
            require_status_checks: req.require_status_checks,
            prevent_force_push: req.prevent_force_push,
            prevent_deletion: req.prevent_deletion,
        },
    )
    .await
    .map_err(|e| (StatusCode::CONFLICT, e.to_string()))?;

    Ok((
        StatusCode::CREATED,
        Json(ProtectionResponse {
            id: protection.id.to_string(),
            pattern: protection.pattern,
            require_pr: protection.require_pr,
            required_approvals: protection.required_approvals,
            require_status_checks: protection.require_status_checks,
            prevent_force_push: protection.prevent_force_push,
            prevent_deletion: protection.prevent_deletion,
        }),
    ))
}

async fn delete_protection(
    State(state): State<AppState>,
    Path((owner, name, protection_id)): Path<(String, String, String)>,
    AuthUser(user): AuthUser,
) -> Result<StatusCode, (StatusCode, String)> {
    let owner_user = delta_core::db::user::get_by_username(&state.db, &owner)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "user not found".into()))?;

    if user.id != owner_user.id {
        return Err((StatusCode::FORBIDDEN, "not the repository owner".into()));
    }

    // Verify the repo exists and protection belongs to it
    let owner_id = owner_user.id.to_string();
    let repo = delta_core::db::repo::get_by_owner_and_name(&state.db, &owner_id, &name)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "repository not found".into()))?;

    // Verify protection belongs to this repo before deleting
    let protections =
        delta_core::db::branch_protection::list_for_repo(&state.db, &repo.id.to_string())
            .await
            .map_err(|e| {
                tracing::error!("failed to list branch protections: {}", e);
                (StatusCode::INTERNAL_SERVER_ERROR, "internal server error".into())
            })?;
    if !protections
        .iter()
        .any(|p| p.id.to_string() == protection_id)
    {
        return Err((StatusCode::NOT_FOUND, "protection rule not found".into()));
    }

    delta_core::db::branch_protection::delete(&state.db, &protection_id)
        .await
        .map_err(|e| (StatusCode::NOT_FOUND, e.to_string()))?;

    Ok(StatusCode::NO_CONTENT)
}

//! Git smart HTTP transport routes.
//!
//! These routes implement the git smart HTTP protocol, enabling standard
//! git clients to clone, fetch, and push via HTTP.
//!
//! Routes:
//!   GET  /{owner}/{name}.git/info/refs?service=git-upload-pack
//!   GET  /{owner}/{name}.git/info/refs?service=git-receive-pack
//!   POST /{owner}/{name}.git/git-upload-pack
//!   POST /{owner}/{name}.git/git-receive-pack

use axum::{
    Router,
    body::Bytes,
    extract::{Path, Query, State},
    http::{HeaderMap, StatusCode, header},
    response::{IntoResponse, Response},
    routing::{get, post},
};
use serde::Deserialize;

use crate::state::AppState;

pub fn router() -> Router<AppState> {
    Router::new()
        .route("/{owner}/{name}.git/info/refs", get(info_refs))
        .route("/{owner}/{name}.git/git-upload-pack", post(upload_pack))
        .route("/{owner}/{name}.git/git-receive-pack", post(receive_pack))
}

#[derive(Deserialize)]
struct InfoRefsQuery {
    service: String,
}

async fn info_refs(
    State(state): State<AppState>,
    Path((owner, name)): Path<(String, String)>,
    Query(query): Query<InfoRefsQuery>,
    headers: HeaderMap,
) -> Result<Response, (StatusCode, String)> {
    // Check repo exists
    let repo_path = state
        .repo_host
        .repo_path(&owner, &name)
        .map_err(|e| (StatusCode::BAD_REQUEST, e.to_string()))?;
    if !repo_path.exists() {
        return Err((StatusCode::NOT_FOUND, "repository not found".into()));
    }

    // For receive-pack (push), require authentication
    if query.service == "git-receive-pack" {
        authenticate_git_request(&state, &headers, &owner)
            .await
            .map_err(|e| (StatusCode::UNAUTHORIZED, e))?;
    } else {
        // For upload-pack (clone/fetch), check visibility
        check_read_access(&state, &owner, &name, &headers).await?;
    }

    let body = delta_vcs::protocol::advertise_refs(&repo_path, &query.service)
        .await
        .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, e.to_string()))?;

    let content_type = format!("application/x-{}-advertisement", query.service);
    Ok((
        StatusCode::OK,
        [
            (header::CONTENT_TYPE, content_type),
            (header::CACHE_CONTROL, "no-cache".into()),
        ],
        body,
    )
        .into_response())
}

async fn upload_pack(
    State(state): State<AppState>,
    Path((owner, name)): Path<(String, String)>,
    headers: HeaderMap,
    body: Bytes,
) -> Result<Response, (StatusCode, String)> {
    let repo_path = state
        .repo_host
        .repo_path(&owner, &name)
        .map_err(|e| (StatusCode::BAD_REQUEST, e.to_string()))?;
    if !repo_path.exists() {
        return Err((StatusCode::NOT_FOUND, "repository not found".into()));
    }

    check_read_access(&state, &owner, &name, &headers).await?;

    let output = delta_vcs::protocol::upload_pack(&repo_path, &body)
        .await
        .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, e.to_string()))?;

    Ok((
        StatusCode::OK,
        [(
            header::CONTENT_TYPE,
            "application/x-git-upload-pack-result".to_string(),
        )],
        output,
    )
        .into_response())
}

async fn receive_pack(
    State(state): State<AppState>,
    Path((owner, name)): Path<(String, String)>,
    headers: HeaderMap,
    body: Bytes,
) -> Result<Response, (StatusCode, String)> {
    let repo_path = state
        .repo_host
        .repo_path(&owner, &name)
        .map_err(|e| (StatusCode::BAD_REQUEST, e.to_string()))?;
    if !repo_path.exists() {
        return Err((StatusCode::NOT_FOUND, "repository not found".into()));
    }

    // Push always requires auth
    let user = authenticate_git_request(&state, &headers, &owner)
        .await
        .map_err(|e| (StatusCode::UNAUTHORIZED, e))?;

    let output = delta_vcs::protocol::receive_pack(&repo_path, &body)
        .await
        .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, e.to_string()))?;

    // Fire webhooks and trigger pipelines asynchronously
    let db = state.db.clone();
    let owner_clone = owner.clone();
    let name_clone = name.clone();
    let pusher = user;
    let repo_path_clone = repo_path.clone();
    let secrets_key = state.config.auth.secrets_key.clone();
    tokio::spawn(async move {
        if let Err(e) = dispatch_push_webhooks(&db, &owner_clone, &name_clone, &pusher).await {
            tracing::warn!("webhook dispatch failed: {}", e);
        }
        if let Err(e) = dispatch_push_pipelines(
            &db,
            &owner_clone,
            &name_clone,
            &repo_path_clone,
            &secrets_key,
        )
        .await
        {
            tracing::warn!("pipeline dispatch failed: {}", e);
        }
    });

    Ok((
        StatusCode::OK,
        [(
            header::CONTENT_TYPE,
            "application/x-git-receive-pack-result".to_string(),
        )],
        output,
    )
        .into_response())
}

/// Authenticate a git HTTP request using Basic auth (username + token).
async fn authenticate_git_request(
    state: &AppState,
    headers: &HeaderMap,
    expected_owner: &str,
) -> std::result::Result<String, String> {
    let auth_header = headers
        .get(header::AUTHORIZATION)
        .and_then(|v| v.to_str().ok())
        .ok_or("authentication required")?;

    let credentials = auth_header
        .strip_prefix("Basic ")
        .ok_or("invalid auth format — use Basic auth with token as password")?;

    let decoded = base64::Engine::decode(&base64::engine::general_purpose::STANDARD, credentials)
        .map_err(|_| "invalid base64 credentials".to_string())?;

    let decoded_str =
        String::from_utf8(decoded).map_err(|_| "invalid utf-8 credentials".to_string())?;

    // Format: username:token
    let (username, token) = decoded_str
        .split_once(':')
        .ok_or("invalid credential format")?;

    let user = crate::auth::authenticate_token(&state.db, token)
        .await
        .map_err(|_| "invalid or expired token".to_string())?;

    if user.username != username {
        return Err("username mismatch".to_string());
    }

    // For push, verify ownership
    if user.username != expected_owner {
        // TODO: check collaborator access
        return Err("you don't have push access to this repository".to_string());
    }

    Ok(user.username)
}

/// Check read access — public repos are open, private repos need auth.
async fn check_read_access(
    state: &AppState,
    owner: &str,
    name: &str,
    headers: &HeaderMap,
) -> std::result::Result<(), (StatusCode, String)> {
    // Look up repo visibility
    let owner_user = delta_core::db::user::get_by_username(&state.db, owner).await;

    if let Ok(owner_user) = owner_user {
        let owner_id = owner_user.id.to_string();
        if let Ok(repo) =
            delta_core::db::repo::get_by_owner_and_name(&state.db, &owner_id, name).await
            && repo.visibility == delta_core::models::repo::Visibility::Public
        {
            return Ok(());
        }
    }

    // Private or unknown — require auth
    authenticate_git_request(state, headers, owner)
        .await
        .map(|_| ())
        .map_err(|e| (StatusCode::UNAUTHORIZED, e))
}

/// Check if a host is in the 172.16.0.0/12 private range (172.16.x - 172.31.x).
fn is_private_172(host: &str) -> bool {
    if let Some(rest) = host.strip_prefix("172.")
        && let Some(octet_str) = rest.split('.').next()
        && let Ok(octet) = octet_str.parse::<u8>()
    {
        return (16..=31).contains(&octet);
    }
    false
}

/// Check if a URL targets a private/internal network (SSRF protection).
pub fn is_private_url(url_str: &str) -> bool {
    let Ok(url) = url::Url::parse(url_str) else {
        return true; // Reject unparseable URLs
    };
    let Some(host) = url.host_str() else {
        return true;
    };
    host == "localhost"
        || host == "127.0.0.1"
        || host == "::1"
        || host == "[::1]"
        || host == "0.0.0.0"
        || host.starts_with("10.")
        || host.starts_with("192.168.")
        || host.starts_with("169.254.")
        || host.starts_with("fe80:")
        || host.starts_with("fc00:")
        || host.starts_with("fd")
        || is_private_172(host)
        || host.ends_with(".local")
        || host.ends_with(".internal")
}

/// Dispatch push webhooks for a repository.
async fn dispatch_push_webhooks(
    db: &sqlx::SqlitePool,
    owner: &str,
    name: &str,
    pusher: &str,
) -> delta_core::Result<()> {
    let owner_user = delta_core::db::user::get_by_username(db, owner).await?;
    let owner_id = owner_user.id.to_string();
    let repo = delta_core::db::repo::get_by_owner_and_name(db, &owner_id, name).await?;
    let repo_id = repo.id.to_string();

    let webhooks = delta_core::db::webhook::get_for_event(db, &repo_id, "push").await?;
    if webhooks.is_empty() {
        return Ok(());
    }

    let payload = serde_json::json!({
        "event": "push",
        "repo_owner": owner,
        "repo_name": name,
        "pusher": pusher,
        "timestamp": chrono::Utc::now().to_rfc3339(),
    });
    let payload_str = serde_json::to_string(&payload)?;

    let client = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(10))
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .map_err(|e| delta_core::DeltaError::Storage(format!("HTTP client error: {e}")))?;

    for webhook in webhooks {
        // Validate webhook URL: must be HTTP(S) and not target private networks
        if !webhook.url.starts_with("https://") && !webhook.url.starts_with("http://") {
            tracing::warn!(webhook_id = %webhook.id, "skipping webhook with non-HTTP URL");
            continue;
        }
        if is_private_url(&webhook.url) {
            tracing::warn!(webhook_id = %webhook.id, "skipping webhook targeting private network");
            continue;
        }

        // Compute HMAC signature if webhook has a secret
        let signature = webhook.secret.as_deref().map(|secret| {
            use blake3::Hasher;
            let mut hasher = Hasher::new_keyed(&blake3::hash(secret.as_bytes()).as_bytes().clone());
            hasher.update(payload_str.as_bytes());
            hasher.finalize().to_hex().to_string()
        });

        let mut req_builder = client
            .post(&webhook.url)
            .header("Content-Type", "application/json")
            .header("X-Delta-Event", "push");

        if let Some(sig) = &signature {
            req_builder = req_builder.header("X-Delta-Signature", sig.as_str());
        }

        let resp = req_builder.body(payload_str.clone()).send().await;

        let (status, body) = match resp {
            Ok(r) => {
                let status = r.status().as_u16() as i32;
                let body = r.text().await.unwrap_or_else(|e| e.to_string());
                (Some(status), Some(body))
            }
            Err(e) => {
                tracing::warn!(webhook_id = %webhook.id, "webhook delivery failed: {}", e);
                (None, Some(e.to_string()))
            }
        };

        let _ = delta_core::db::webhook::record_delivery(
            db,
            &webhook.id,
            "push",
            &payload_str,
            status,
            body.as_deref(),
        )
        .await;
    }

    Ok(())
}

/// Trigger CI/CD pipelines for a push event.
async fn dispatch_push_pipelines(
    db: &sqlx::SqlitePool,
    owner: &str,
    name: &str,
    repo_path: &std::path::Path,
    secrets_key: &str,
) -> std::result::Result<(), String> {
    // Resolve repo
    let owner_user = delta_core::db::user::get_by_username(db, owner)
        .await
        .map_err(|e| format!("failed to resolve owner: {e}"))?;
    let owner_id = owner_user.id.to_string();
    let repo = delta_core::db::repo::get_by_owner_and_name(db, &owner_id, name)
        .await
        .map_err(|e| format!("failed to resolve repo: {e}"))?;
    let repo_id = repo.id.to_string();

    // Get HEAD branch name
    let branch = delta_vcs::refs::head_branch(repo_path).unwrap_or_else(|| "main".into());

    // Get HEAD commit SHA
    let commit_sha = delta_vcs::refs::head_commit(repo_path)
        .ok()
        .flatten()
        .unwrap_or_default();

    if commit_sha.is_empty() {
        return Ok(());
    }

    // Decrypt repo secrets for pipeline env
    let encryption_key = delta_core::crypto::derive_key(secrets_key);
    let mut secrets = std::collections::HashMap::new();
    if let Ok(encrypted_secrets) = delta_core::db::secret::get_all_values(db, &repo_id).await {
        for (key, encrypted_value) in encrypted_secrets {
            if let Ok(value) = delta_core::crypto::decrypt(&encryption_key, &encrypted_value) {
                secrets.insert(key, value);
            }
        }
    }

    let ctx = delta_ci::runner::PipelineContext {
        pool: db,
        repo_id: &repo_id,
        repo_path,
        commit_sha: &commit_sha,
        secrets: &secrets,
    };
    delta_ci::runner::run_push_pipelines(&ctx, &branch).await;
    Ok(())
}

