#[derive(Deserialize)]
struct SubmitReviewRequest {
    state: String,
    body: Option<String>,
}

async fn submit_review(
    State(state): State<AppState>,
    Path((owner, name, number)): Path<(String, String, i64)>,
    AuthUser(user): AuthUser,
    Json(req): Json<SubmitReviewRequest>,
) -> Result<(StatusCode, Json<ReviewResponse>), (StatusCode, String)> {
    let (repo, _) = resolve_repo_authed(&state, &owner, &name, &user).await?;
    let repo_id = repo.id.to_string();

    let pr = db::pull_request::get_by_number(&state.db, &repo_id, number)
        .await
        .map_err(|e| (StatusCode::NOT_FOUND, e.to_string()))?;

    // Can't review your own PR
    if pr.author_id == user.id {
        return Err((
            StatusCode::CONFLICT,
            "cannot review your own pull request".into(),
        ));
    }

    let review_state = match req.state.as_str() {
        "approved" => ReviewState::Approved,
        "changes_requested" => ReviewState::ChangesRequested,
        _ => ReviewState::Commented,
    };

    let review = db::pull_request::submit_review(
        &state.db,
        &pr.id.to_string(),
        &user.id.to_string(),
        review_state,
        req.body.as_deref(),
    )
    .await
    .map_err(|e| {
        tracing::error!("failed to submit review: {}", e);
        (StatusCode::INTERNAL_SERVER_ERROR, "internal server error".into())
    })?;

    Ok((
        StatusCode::CREATED,
        Json(ReviewResponse {
            id: review.id.to_string(),
            reviewer: user.username,
            state: review.state.as_str().to_string(),
            body: review.body,
            created_at: review.created_at.to_rfc3339(),
        }),
    ))
}

use axum::{
    Json, Router,
    extract::{Path, State},
    http::StatusCode,
    routing::get,
};
use delta_core::db;
use delta_core::models::repo::Visibility;
use serde::{Deserialize, Serialize};

use crate::extractors::{AuthUser, MaybeAuthUser};
use crate::state::AppState;

pub fn router() -> Router<AppState> {
    Router::new()
        .route("/", get(list_repos).post(create_repo))
        .route(
            "/{owner}/{name}",
            get(get_repo).put(update_repo).delete(delete_repo),
        )
}

#[derive(Serialize)]
struct RepoResponse {
    id: String,
    owner: String,
    name: String,
    full_name: String,
    description: Option<String>,
    visibility: String,
    default_branch: String,
    created_at: String,
    updated_at: String,
}

impl RepoResponse {
    fn from_repo(repo: delta_core::models::repo::Repository, owner_name: &str) -> Self {
        Self {
            id: repo.id.to_string(),
            full_name: format!("{}/{}", owner_name, repo.name),
            owner: owner_name.to_string(),
            name: repo.name,
            description: repo.description,
            visibility: repo.visibility.as_str().to_string(),
            default_branch: repo.default_branch,
            created_at: repo.created_at.to_rfc3339(),
            updated_at: repo.updated_at.to_rfc3339(),
        }
    }
}

async fn list_repos(
    State(state): State<AppState>,
    MaybeAuthUser(user): MaybeAuthUser,
) -> Result<Json<Vec<RepoResponse>>, (StatusCode, String)> {
    let viewer_id = user.as_ref().map(|u| u.id.to_string());
    let repos = db::repo::list_visible(&state.db, viewer_id.as_deref())
        .await
        .map_err(|e| {
            tracing::error!("failed to list repos: {}", e);
            (StatusCode::INTERNAL_SERVER_ERROR, "internal server error".into())
        })?;

    // We need owner usernames — for now use the owner field (which stores owner_id)
    // TODO: join with users table for proper username resolution
    let mut responses = Vec::new();
    for repo in repos {
        let owner_name = db::user::get_by_id(&state.db, &repo.owner)
            .await
            .map(|u| u.username)
            .unwrap_or_else(|_| repo.owner.clone());
        responses.push(RepoResponse::from_repo(repo, &owner_name));
    }

    Ok(Json(responses))
}

#[derive(Deserialize)]
struct CreateRepoRequest {
    name: String,
    description: Option<String>,
    #[serde(default = "default_visibility")]
    visibility: String,
}

fn default_visibility() -> String {
    "private".to_string()
}

async fn create_repo(
    State(state): State<AppState>,
    AuthUser(user): AuthUser,
    Json(req): Json<CreateRepoRequest>,
) -> Result<(StatusCode, Json<RepoResponse>), (StatusCode, String)> {
    if req.name.is_empty()
        || req.name.len() > 100
        || req.name.starts_with('-')
        || req.name.starts_with('.')
        || !req
            .name
            .chars()
            .all(|c| c.is_ascii_alphanumeric() || c == '-' || c == '_' || c == '.')
    {
        return Err((StatusCode::BAD_REQUEST, "invalid repository name".into()));
    }
    let visibility = match req.visibility.as_str() {
        "public" => Visibility::Public,
        "internal" => Visibility::Internal,
        _ => Visibility::Private,
    };

    let user_id = user.id.to_string();
    let repo = db::repo::create(
        &state.db,
        &user_id,
        &req.name,
        req.description.as_deref(),
        visibility,
    )
    .await
    .map_err(|e| (StatusCode::CONFLICT, e.to_string()))?;

    // Initialize bare git repo on disk
    if let Err(e) = state.repo_host.init_bare(&user.username, &req.name) {
        tracing::warn!("failed to init bare repo on disk: {}", e);
    }

    Ok((
        StatusCode::CREATED,
        Json(RepoResponse::from_repo(repo, &user.username)),
    ))
}

async fn get_repo(
    State(state): State<AppState>,
    MaybeAuthUser(user): MaybeAuthUser,
    Path((owner, name)): Path<(String, String)>,
) -> Result<Json<RepoResponse>, (StatusCode, String)> {
    // Look up owner by username
    let owner_user = db::user::get_by_username(&state.db, &owner)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, format!("user '{}' not found", owner)))?;

    let owner_id = owner_user.id.to_string();
    let repo = db::repo::get_by_owner_and_name(&state.db, &owner_id, &name)
        .await
        .map_err(|_| {
            (
                StatusCode::NOT_FOUND,
                format!("repository '{}/{}' not found", owner, name),
            )
        })?;

    // Check visibility — non-public repos require owner
    if repo.visibility != Visibility::Public {
        let is_owner = user.as_ref().is_some_and(|u| u.id == owner_user.id);
        if !is_owner {
            return Err((
                StatusCode::NOT_FOUND,
                format!("repository '{}/{}' not found", owner, name),
            ));
        }
    }

    Ok(Json(RepoResponse::from_repo(repo, &owner)))
}

#[derive(Deserialize)]
struct UpdateRepoRequest {
    description: Option<String>,
    visibility: Option<String>,
    default_branch: Option<String>,
}

async fn update_repo(
    State(state): State<AppState>,
    AuthUser(user): AuthUser,
    Path((owner, name)): Path<(String, String)>,
    Json(req): Json<UpdateRepoRequest>,
) -> Result<Json<RepoResponse>, (StatusCode, String)> {
    let owner_user = db::user::get_by_username(&state.db, &owner)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, format!("user '{}' not found", owner)))?;

    if user.id != owner_user.id {
        return Err((StatusCode::FORBIDDEN, "not the repository owner".into()));
    }

    let owner_id = owner_user.id.to_string();
    let repo = db::repo::get_by_owner_and_name(&state.db, &owner_id, &name)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "repository not found".to_string()))?;

    let visibility = req.visibility.as_deref().map(|v| match v {
        "public" => Visibility::Public,
        "internal" => Visibility::Internal,
        _ => Visibility::Private,
    });

    let updated = db::repo::update(
        &state.db,
        &repo.id.to_string(),
        req.description.as_deref(),
        visibility,
        req.default_branch.as_deref(),
    )
    .await
    .map_err(|e| {
        tracing::error!("failed to update repo: {}", e);
        (StatusCode::INTERNAL_SERVER_ERROR, "internal server error".into())
    })?;

    Ok(Json(RepoResponse::from_repo(updated, &owner)))
}

async fn delete_repo(
    State(state): State<AppState>,
    AuthUser(user): AuthUser,
    Path((owner, name)): Path<(String, String)>,
) -> Result<StatusCode, (StatusCode, String)> {
    let owner_user = db::user::get_by_username(&state.db, &owner)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, format!("user '{}' not found", owner)))?;

    if user.id != owner_user.id {
        return Err((StatusCode::FORBIDDEN, "not the repository owner".into()));
    }

    let owner_id = owner_user.id.to_string();
    let repo = db::repo::get_by_owner_and_name(&state.db, &owner_id, &name)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "repository not found".into()))?;

    db::repo::delete(&state.db, &repo.id.to_string())
        .await
        .map_err(|e| {
            tracing::error!("failed to delete repo: {}", e);
            (StatusCode::INTERNAL_SERVER_ERROR, "internal server error".into())
        })?;

    // Remove from disk
    if let Err(e) = state.repo_host.delete(&owner, &name) {
        tracing::warn!("failed to delete repo from disk: {}", e);
    }

    Ok(StatusCode::NO_CONTENT)
}

use axum::{
    Json, Router,
    extract::{Path, State},
    http::StatusCode,
    routing::get,
};
use delta_core::db;
use delta_core::models::pull_request::CheckState;
use delta_core::models::repo::Visibility;
use serde::{Deserialize, Serialize};

use crate::extractors::AuthUser;
use crate::state::AppState;

pub fn router() -> Router<AppState> {
    Router::new().route(
        "/{owner}/{name}/commits/{sha}/statuses",
        get(list_statuses).post(create_status),
    )
}

#[derive(Serialize)]
struct StatusResponse {
    id: String,
    context: String,
    state: String,
    description: Option<String>,
    target_url: Option<String>,
    created_at: String,
    updated_at: String,
}

async fn list_statuses(
    State(state): State<AppState>,
    Path((owner, name, sha)): Path<(String, String, String)>,
) -> Result<Json<Vec<StatusResponse>>, (StatusCode, String)> {
    let owner_user = db::user::get_by_username(&state.db, &owner)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "user not found".into()))?;
    let owner_id = owner_user.id.to_string();
    let repo = db::repo::get_by_owner_and_name(&state.db, &owner_id, &name)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "repository not found".into()))?;

    // Reject requests for private repos on unauthenticated endpoint
    if repo.visibility != Visibility::Public {
        return Err((StatusCode::NOT_FOUND, "repository not found".into()));
    }

    let checks = db::status_check::get_for_commit(&state.db, &repo.id.to_string(), &sha)
        .await
        .map_err(|e| {
            tracing::error!("failed to fetch status checks: {}", e);
            (
                StatusCode::INTERNAL_SERVER_ERROR,
                "internal server error".into(),
            )
        })?;

    Ok(Json(
        checks
            .into_iter()
            .map(|c| StatusResponse {
                id: c.id.to_string(),
                context: c.context,
                state: c.state.as_str().to_string(),
                description: c.description,
                target_url: c.target_url,
                created_at: c.created_at.to_rfc3339(),
                updated_at: c.updated_at.to_rfc3339(),
            })
            .collect(),
    ))
}

#[derive(Deserialize)]
struct CreateStatusRequest {
    context: String,
    state: String,
    description: Option<String>,
    target_url: Option<String>,
}

async fn create_status(
    State(state): State<AppState>,
    Path((owner, name, sha)): Path<(String, String, String)>,
    AuthUser(user): AuthUser,
    Json(req): Json<CreateStatusRequest>,
) -> Result<(StatusCode, Json<StatusResponse>), (StatusCode, String)> {
    let owner_user = db::user::get_by_username(&state.db, &owner)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "user not found".into()))?;
    if user.id != owner_user.id {
        return Err((StatusCode::FORBIDDEN, "not the repository owner".into()));
    }
    let owner_id = owner_user.id.to_string();
    let repo = db::repo::get_by_owner_and_name(&state.db, &owner_id, &name)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "repository not found".into()))?;

    let check_state = match req.state.as_str() {
        "success" => CheckState::Success,
        "failure" => CheckState::Failure,
        "error" => CheckState::Error,
        _ => CheckState::Pending,
    };

    let check = db::status_check::upsert(
        &state.db,
        &repo.id.to_string(),
        &sha,
        &req.context,
        check_state,
        req.description.as_deref(),
        req.target_url.as_deref(),
    )
    .await
    .map_err(|e| {
        tracing::error!("failed to upsert status check: {}", e);
        (StatusCode::INTERNAL_SERVER_ERROR, "internal server error".into())
    })?;

    Ok((
        StatusCode::CREATED,
        Json(StatusResponse {
            id: check.id.to_string(),
            context: check.context,
            state: check.state.as_str().to_string(),
            description: check.description,
            target_url: check.target_url,
            created_at: check.created_at.to_rfc3339(),
            updated_at: check.updated_at.to_rfc3339(),
        }),
    ))
}

use axum::{
    Json, Router,
    extract::{Path, State},
    http::StatusCode,
    routing::get,
};
use serde::{Deserialize, Serialize};

use crate::extractors::AuthUser;
use crate::state::AppState;

pub fn router() -> Router<AppState> {
    Router::new()
        .route(
            "/{owner}/{name}/webhooks",
            get(list_webhooks).post(create_webhook),
        )
        .route(
            "/{owner}/{name}/webhooks/{webhook_id}",
            axum::routing::delete(delete_webhook),
        )
}

#[derive(Serialize)]
struct WebhookResponse {
    id: String,
    url: String,
    events: Vec<String>,
    active: bool,
    created_at: String,
}

async fn list_webhooks(
    State(state): State<AppState>,
    Path((owner, name)): Path<(String, String)>,
    AuthUser(user): AuthUser,
) -> Result<Json<Vec<WebhookResponse>>, (StatusCode, String)> {
    let (repo, _) = resolve_owned_repo(&state, &owner, &name, &user).await?;

    let webhooks = delta_core::db::webhook::list_for_repo(&state.db, &repo.id.to_string())
        .await
        .map_err(|e| {
            tracing::error!("failed to list webhooks: {}", e);
            (StatusCode::INTERNAL_SERVER_ERROR, "internal server error".into())
        })?;

    Ok(Json(
        webhooks
            .into_iter()
            .map(|w| {
                let events: Vec<String> = serde_json::from_str(&w.events).unwrap_or_default();
                WebhookResponse {
                    id: w.id,
                    url: w.url,
                    events,
                    active: w.active,
                    created_at: w.created_at,
                }
            })
            .collect(),
    ))
}

#[derive(Deserialize)]
struct CreateWebhookRequest {
    url: String,
    secret: Option<String>,
    #[serde(default = "default_events")]
    events: Vec<String>,
}

fn default_events() -> Vec<String> {
    vec!["push".into()]
}

async fn create_webhook(
    State(state): State<AppState>,
    Path((owner, name)): Path<(String, String)>,
    AuthUser(user): AuthUser,
    Json(req): Json<CreateWebhookRequest>,
) -> Result<(StatusCode, Json<WebhookResponse>), (StatusCode, String)> {
    let (repo, _) = resolve_owned_repo(&state, &owner, &name, &user).await?;

    // Validate webhook URL: must be HTTP(S) and not target private networks
    if !req.url.starts_with("https://") && !req.url.starts_with("http://") {
        return Err((
            StatusCode::BAD_REQUEST,
            "webhook URL must use http or https".into(),
        ));
    }
    if crate::routes::git::is_private_url(&req.url) {
        return Err((
            StatusCode::BAD_REQUEST,
            "webhook URL must not target private networks".into(),
        ));
    }

    let events_json =
        serde_json::to_string(&req.events).map_err(|e| (StatusCode::BAD_REQUEST, e.to_string()))?;

    let id = delta_core::db::webhook::create(
        &state.db,
        &repo.id.to_string(),
        &req.url,
        req.secret.as_deref(),
        &events_json,
    )
    .await
    .map_err(|e| {
        tracing::error!("failed to create webhook: {}", e);
        (StatusCode::INTERNAL_SERVER_ERROR, "internal server error".into())
    })?;

    Ok((
        StatusCode::CREATED,
        Json(WebhookResponse {
            id,
            url: req.url,
            events: req.events,
            active: true,
            created_at: chrono::Utc::now().to_rfc3339(),
        }),
    ))
}

async fn delete_webhook(
    State(state): State<AppState>,
    Path((owner, name, webhook_id)): Path<(String, String, String)>,
    AuthUser(user): AuthUser,
) -> Result<StatusCode, (StatusCode, String)> {
    let (repo, _) = resolve_owned_repo(&state, &owner, &name, &user).await?;

    delta_core::db::webhook::delete(&state.db, &webhook_id, &repo.id.to_string())
        .await
        .map_err(|e| (StatusCode::NOT_FOUND, e.to_string()))?;

    Ok(StatusCode::NO_CONTENT)
}

/// Helper: resolve repo and verify ownership.
async fn resolve_owned_repo(
    state: &AppState,
    owner: &str,
    name: &str,
    user: &delta_core::models::user::User,
) -> Result<
    (
        delta_core::models::repo::Repository,
        delta_core::models::user::User,
    ),
    (StatusCode, String),
> {
    let owner_user = delta_core::db::user::get_by_username(&state.db, owner)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "user not found".into()))?;

    if user.id != owner_user.id {
        return Err((StatusCode::FORBIDDEN, "not the repository owner".into()));
    }

    let owner_id = owner_user.id.to_string();
    let repo = delta_core::db::repo::get_by_owner_and_name(&state.db, &owner_id, name)
        .await
        .map_err(|_| (StatusCode::NOT_FOUND, "repository not found".into()))?;

    Ok((repo, owner_user))
}

