    resource_type: Option<&str>,
    limit: i64,
    offset: i64,
) -> Result<Vec<AuditEntry>> {
    let rows = match (user_id, resource_type) {
        (Some(uid), Some(rt)) => {
            sqlx::query_as::<_, AuditRow>(
                "SELECT * FROM audit_log WHERE user_id = ? AND resource_type = ? ORDER BY created_at DESC LIMIT ? OFFSET ?",
