            .bind(uid)
            .bind(limit)
            .bind(offset)
            .fetch_all(pool)
            .await
        }
        (None, Some(rt)) => {
            sqlx::query_as::<_, AuditRow>(
                "SELECT * FROM audit_log WHERE resource_type = ? ORDER BY created_at DESC LIMIT ? OFFSET ?",
