//! Git merge execution for pull requests.

use delta_core::{DeltaError, Result};
use std::path::Path;
use std::process::Stdio;
use tokio::process::Command;

use crate::validate::validate_ref;

/// Validate author name/email to prevent git config injection.
fn validate_author(name: &str, email: &str) -> Result<()> {
    if name.is_empty() || email.is_empty() {
        return Err(DeltaError::InvalidRef(
            "author name/email cannot be empty".into(),
        ));
    }
    // Reject control characters and characters that could be interpreted as git options
    for (label, value) in [("name", name), ("email", email)] {
        if value.starts_with('-') {
            return Err(DeltaError::InvalidRef(format!(
                "author {} cannot start with '-'",
                label
            )));
        }
        if value.contains('\0') || value.contains('\n') || value.contains('\r') {
            return Err(DeltaError::InvalidRef(format!(
                "author {} contains invalid characters",
                label
            )));
        }
    }
    Ok(())
}

/// Execute a merge in a bare repository using a temporary worktree.
/// Returns the resulting merge commit SHA.
pub async fn execute_merge(
    repo_path: &Path,
    base_branch: &str,
    head_branch: &str,
    strategy: MergeMode,
    merge_message: &str,
    author_name: &str,
    author_email: &str,
) -> Result<String> {
    validate_ref(base_branch)?;
    validate_ref(head_branch)?;
    validate_author(author_name, author_email)?;

    let tmp_dir = tempfile::tempdir()
        .map_err(|e| DeltaError::Storage(format!("failed to create temp dir: {}", e)))?;
    let worktree_path = tmp_dir.path().join("merge-worktree");
    let worktree_str = worktree_path
        .to_str()
        .ok_or_else(|| DeltaError::Storage("worktree path is not valid UTF-8".into()))?;

    // Add worktree at the base branch
    run_git(repo_path, &["worktree", "add", worktree_str, base_branch]).await?;

    // Set author info
    run_git_in(&worktree_path, &["config", "user.name", author_name]).await?;
    run_git_in(&worktree_path, &["config", "user.email", author_email]).await?;

    let merge_result = do_merge(&worktree_path, head_branch, strategy, merge_message).await;

    if let Err(e) = merge_result {
        let _ = run_git(repo_path, &["worktree", "remove", "--force", worktree_str]).await;
        return Err(e);
    }

    // Get the resulting commit SHA
    let sha = run_git_output(&worktree_path, &["rev-parse", "HEAD"]).await?;

    // Clean up worktree
    let _ = run_git(repo_path, &["worktree", "remove", "--force", worktree_str]).await;

    Ok(sha.trim().to_string())
}

async fn do_merge(
    worktree: &Path,
    head_branch: &str,
    strategy: MergeMode,
    message: &str,
) -> Result<()> {
    match strategy {
        MergeMode::Merge => {
            // Try direct branch ref first
            run_git_in(worktree, &["merge", "--no-ff", "-m", message, head_branch]).await
        }
        MergeMode::Squash => {
            run_git_in(worktree, &["merge", "--squash", head_branch]).await?;
            run_git_in(worktree, &["commit", "-m", message]).await
        }
        MergeMode::Rebase => run_git_in(worktree, &["rebase", head_branch]).await,
    }
}

#[derive(Debug, Clone, Copy)]
pub enum MergeMode {
    Merge,
    Squash,
    Rebase,
}

async fn run_git(repo_path: &Path, args: &[&str]) -> Result<()> {
    let output = Command::new("git")
        .args(args)
        .current_dir(repo_path)
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .output()
        .await
        .map_err(|e| DeltaError::Storage(format!("git failed: {}", e)))?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(DeltaError::Storage(format!(
            "git {} failed: {}",
            args.first().unwrap_or(&""),
            stderr
        )));
    }
    Ok(())
}

async fn run_git_in(worktree: &Path, args: &[&str]) -> Result<()> {
    let output = Command::new("git")
        .args(args)
        .current_dir(worktree)
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .output()
        .await
        .map_err(|e| DeltaError::Storage(format!("git failed: {}", e)))?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(DeltaError::Storage(format!(
            "git {} failed: {}",
            args.first().unwrap_or(&""),
            stderr
        )));
    }
    Ok(())
}

async fn run_git_output(worktree: &Path, args: &[&str]) -> Result<String> {
    let output = Command::new("git")
        .args(args)
        .current_dir(worktree)
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .output()
        .await
        .map_err(|e| DeltaError::Storage(format!("git failed: {}", e)))?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(DeltaError::Storage(format!(
            "git {} failed: {}",
            args.first().unwrap_or(&""),
            stderr
        )));
    }
    Ok(String::from_utf8_lossy(&output.stdout).to_string())
}

//! Git smart HTTP protocol handlers.
//!
//! Implements the server side of the git smart HTTP transport:
//! - `GET /info/refs?service=git-upload-pack` — ref advertisement for clone/fetch
//! - `GET /info/refs?service=git-receive-pack` — ref advertisement for push
//! - `POST /git-upload-pack` — pack negotiation and data transfer (clone/fetch)
//! - `POST /git-receive-pack` — receive pushed data

use std::path::Path;
use std::process::Stdio;
use tokio::process::Command;

use delta_core::{DeltaError, Result};

/// Run `git-upload-pack --advertise-refs` or `git-receive-pack --advertise-refs`
/// for the info/refs endpoint.
pub async fn advertise_refs(repo_path: &Path, service: &str) -> Result<Vec<u8>> {
    validate_service(service)?;

    let output = Command::new("git")
        .arg(service.strip_prefix("git-").unwrap_or(service))
        .arg("--stateless-rpc")
        .arg("--advertise-refs")
        .arg(repo_path)
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .output()
        .await
        .map_err(|e| DeltaError::Storage(format!("failed to run git: {}", e)))?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(DeltaError::Storage(format!(
            "git {} --advertise-refs failed: {}",
            service, stderr
        )));
    }

    // Build the smart HTTP response:
    // First line: pkt-line with "# service=git-upload-pack\n"
    // Then: flush packet (0000)
    // Then: the ref advertisement from git
    let mut body = Vec::new();
    let service_line = format!("# service={}\n", service);
    write_pkt_line(&mut body, service_line.as_bytes());
    body.extend_from_slice(b"0000");
    body.extend_from_slice(&output.stdout);

    Ok(body)
}

/// Run `git-upload-pack --stateless-rpc` for clone/fetch.
pub async fn upload_pack(repo_path: &Path, input: &[u8]) -> Result<Vec<u8>> {
    run_service_rpc(repo_path, "upload-pack", input).await
}

/// Run `git-receive-pack --stateless-rpc` for push.
pub async fn receive_pack(repo_path: &Path, input: &[u8]) -> Result<Vec<u8>> {
    run_service_rpc(repo_path, "receive-pack", input).await
}

/// Run a git service in stateless RPC mode.
async fn run_service_rpc(repo_path: &Path, service: &str, input: &[u8]) -> Result<Vec<u8>> {
    let mut child = Command::new("git")
        .arg(service)
        .arg("--stateless-rpc")
        .arg(repo_path)
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|e| DeltaError::Storage(format!("failed to spawn git {}: {}", service, e)))?;

    // Write input to stdin
    if let Some(mut stdin) = child.stdin.take() {
        use tokio::io::AsyncWriteExt;
        stdin
            .write_all(input)
            .await
            .map_err(|e| DeltaError::Storage(format!("failed to write to git stdin: {}", e)))?;
        drop(stdin);
    }

    let output = child
        .wait_with_output()
        .await
        .map_err(|e| DeltaError::Storage(format!("git {} failed: {}", service, e)))?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        tracing::warn!(service, %stderr, "git service exited with error");
        // Don't fail — git sometimes returns non-zero for valid operations
        // (e.g., rejected pushes). The client reads the error from stdout.
    }

    Ok(output.stdout)
}

/// Validate that the service name is one of the allowed git services.
fn validate_service(service: &str) -> Result<()> {
    match service {
        "git-upload-pack" | "git-receive-pack" => Ok(()),
        _ => Err(DeltaError::InvalidRef(format!(
            "invalid git service: {}",
            service
        ))),
    }
}

/// Write a pkt-line formatted message.
fn write_pkt_line(buf: &mut Vec<u8>, data: &[u8]) {
    let len = data.len() + 4; // 4 bytes for the length prefix itself
    buf.extend_from_slice(format!("{:04x}", len).as_bytes());
    buf.extend_from_slice(data);
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_validate_service() {
        assert!(validate_service("git-upload-pack").is_ok());
        assert!(validate_service("git-receive-pack").is_ok());
        assert!(validate_service("git-evil-command").is_err());
        assert!(validate_service("rm -rf").is_err());
    }

    #[test]
    fn test_write_pkt_line() {
        let mut buf = Vec::new();
        write_pkt_line(&mut buf, b"# service=git-upload-pack\n");
        let s = String::from_utf8(buf).unwrap();
        // "# service=git-upload-pack\n" is 26 bytes + 4 = 30 = 0x001e
        assert!(s.starts_with("001e"));
        assert!(s.contains("# service=git-upload-pack"));
    }
}

//! Reference (branch/tag) management via gix.

use delta_core::{DeltaError, Result};
use serde::{Deserialize, Serialize};
use std::path::Path;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BranchInfo {
    pub name: String,
    pub commit_id: String,
    pub is_default: bool,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TagInfo {
    pub name: String,
    pub target_id: String,
}

/// List all branches in a bare repository.
pub fn list_branches(repo_path: &Path) -> Result<Vec<BranchInfo>> {
    let repo = gix::open(repo_path)
        .map_err(|e| DeltaError::Storage(format!("failed to open repo: {}", e)))?;

    let head_ref = repo.head_ref().ok().flatten();
    let head_name = head_ref.as_ref().map(|r| r.name().shorten().to_string());

    let refs = repo
        .references()
        .map_err(|e| DeltaError::Storage(e.to_string()))?;

    let branches = refs
        .local_branches()
        .map_err(|e| DeltaError::Storage(e.to_string()))?;

    let mut result = Vec::new();
    for reference in branches.flatten() {
        let name = reference.name().shorten().to_string();
        let commit_id = reference.id().to_hex().to_string();
        let is_default = head_name.as_deref() == Some(name.as_str());
        result.push(BranchInfo {
            name,
            commit_id,
            is_default,
        });
    }

    Ok(result)
}

/// List all tags in a bare repository.
pub fn list_tags(repo_path: &Path) -> Result<Vec<TagInfo>> {
    let repo = gix::open(repo_path)
        .map_err(|e| DeltaError::Storage(format!("failed to open repo: {}", e)))?;

    let refs = repo
        .references()
        .map_err(|e| DeltaError::Storage(e.to_string()))?;

    let tags = refs
        .tags()
        .map_err(|e| DeltaError::Storage(e.to_string()))?;

    let mut result = Vec::new();
    for reference in tags.flatten() {
        let name = reference.name().shorten().to_string();
        let target_id = reference.id().to_hex().to_string();
        result.push(TagInfo { name, target_id });
    }

    Ok(result)
}

/// Get the branch name that HEAD points to (e.g. "main").
/// Returns None for empty repos or detached HEAD.
pub fn head_branch(repo_path: &Path) -> Option<String> {
    let repo = gix::open(repo_path).ok()?;
    let head_ref = repo.head_ref().ok()??;
    Some(head_ref.name().shorten().to_string())
}

/// Get the commit ID that HEAD points to, if any.
pub fn head_commit(repo_path: &Path) -> Result<Option<String>> {
    let repo = gix::open(repo_path)
        .map_err(|e| DeltaError::Storage(format!("failed to open repo: {}", e)))?;

    match repo.head_commit() {
        Ok(commit) => Ok(Some(commit.id().to_hex().to_string())),
        Err(_) => Ok(None), // Empty repo, no commits yet
    }
}

//! Input validation for git operations.

use delta_core::{DeltaError, Result};

/// Validate a git ref name (branch, tag, commit SHA).
/// Prevents git option injection and invalid characters.
pub fn validate_ref(name: &str) -> Result<()> {
    if name.is_empty() {
        return Err(DeltaError::InvalidRef("ref name cannot be empty".into()));
    }
    if name.starts_with('-') {
        return Err(DeltaError::InvalidRef(
            "ref name cannot start with '-'".into(),
        ));
    }
    if name.contains("..") {
        return Err(DeltaError::InvalidRef(
            "ref name cannot contain '..'".into(),
        ));
    }
    if name.contains('\0')
        || name.contains(' ')
        || name.contains('~')
        || name.contains('^')
        || name.contains(':')
        || name.contains('\\')
        || name.contains('\x7f')
    {
        return Err(DeltaError::InvalidRef(
            "ref name contains invalid characters".into(),
        ));
    }
    if name.ends_with('/') || name.ends_with('.') || name.ends_with(".lock") {
        return Err(DeltaError::InvalidRef("ref name has invalid suffix".into()));
    }
    Ok(())
}

/// Validate an owner or repo name for filesystem safety.
/// Only allows alphanumeric, hyphens, underscores, and dots (not leading).
pub fn validate_name(name: &str) -> Result<()> {
    if name.is_empty() {
        return Err(DeltaError::InvalidRef("name cannot be empty".into()));
    }
    if name.starts_with('.') || name.starts_with('-') {
        return Err(DeltaError::InvalidRef(
            "name cannot start with '.' or '-'".into(),
        ));
    }
    if name.contains('/') || name.contains('\\') || name.contains('\0') {
        return Err(DeltaError::InvalidRef(
            "name contains path separators".into(),
        ));
    }
    if name == "." || name == ".." {
        return Err(DeltaError::InvalidRef("name cannot be '.' or '..'".into()));
    }
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_valid_refs() {
        assert!(validate_ref("main").is_ok());
        assert!(validate_ref("feature/my-branch").is_ok());
        assert!(validate_ref("v1.0.0").is_ok());
        assert!(validate_ref("abc123def456").is_ok());
    }

    #[test]
    fn test_invalid_refs() {
        assert!(validate_ref("").is_err());
        assert!(validate_ref("--exec=foo").is_err());
        assert!(validate_ref("-n").is_err());
        assert!(validate_ref("a..b").is_err());
        assert!(validate_ref("ref\0name").is_err());
        assert!(validate_ref("ref name").is_err());
        assert!(validate_ref("ref~1").is_err());
        assert!(validate_ref("ref^2").is_err());
        assert!(validate_ref("ref:name").is_err());
        assert!(validate_ref("name.lock").is_err());
        assert!(validate_ref("name/").is_err());
    }

    #[test]
    fn test_valid_names() {
        assert!(validate_name("alice").is_ok());
        assert!(validate_name("my-repo").is_ok());
        assert!(validate_name("repo_v2").is_ok());
    }

    #[test]
    fn test_invalid_names() {
        assert!(validate_name("").is_err());
        assert!(validate_name("..").is_err());
        assert!(validate_name(".hidden").is_err());
        assert!(validate_name("-leading").is_err());
        assert!(validate_name("../../etc").is_err());
        assert!(validate_name("a/b").is_err());
    }
}

use delta_vcs::RepoHost;
use tempfile::TempDir;

#[test]
fn test_init_bare_creates_valid_git_repo() {
    let tmp = TempDir::new().unwrap();
    let host = RepoHost::new(tmp.path());

    let path = host.init_bare("alice", "myproject").unwrap();
    assert!(path.exists());

    // Should be a valid bare git repo (has HEAD, refs/, objects/)
    assert!(path.join("HEAD").exists());
